 36→/// Distinguishes Docker from Podman for behaviour that differs between the two
 37→/// OCI runtimes (hardening flags, host-gateway resolution, etc.).
 38→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 39→pub(crate) enum BackendKind {
 40→    Docker,
 41→    Podman,
 42→}
 43→
 44→/// Docker/Podman-based sandbox implementation.
 45→///
 46→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 47→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 48→/// this single implementation.  `kind` carries the typed backend identity for
 49→/// behaviour branching without string comparisons.
 50→pub struct DockerSandbox {
 51→    pub config: SandboxConfig,
 52→    kind: BackendKind,
 53→    cli: &'static str,
 54→    backend_label: &'static str,
 55→}
 56→
 57→impl DockerSandbox {
 58→    pub fn new(config: SandboxConfig) -> Self {
 59→        Self {
 60→            config,
 61→            kind: BackendKind::Docker,
 62→            cli: "docker",
 63→            backend_label: "docker",
 64→        }
 65→    }
 66→
 67→    pub fn podman(config: SandboxConfig) -> Self {
 68→        Self {
 69→            config,
 70→            kind: BackendKind::Podman,
 71→            cli: "podman",
 72→            backend_label: "podman",
 73→        }
 74→    }
 75→
 76→    fn image(&self) -> &str {
 77→        self.config
 78→            .image
 79→            .as_deref()
 80→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 81→    }
 82→
 83→    fn container_prefix(&self) -> &str {
 84→        self.config
 85→            .container_prefix
 86→            .as_deref()
 87→            .unwrap_or("moltis-sandbox")
 88→    }
 89→
 90→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 91→        format!("{}-{}", self.container_prefix(), id.key)
 92→    }
 93→
 94→    fn image_repo(&self) -> &str {
 95→        self.container_prefix()
 96→    }
 97→
 98→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
 99→        let guest_path = std::path::Path::new(guest_path);
100→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
101→            || {
102→                resolve_home_persistence_guest_path_on_host(
103→                    &self.config,
104→                    Some(self.cli),
105→                    id,
106→                    guest_path,
107→                )
108→            },
109→        )
110→    }
111→
112→    pub(crate) fn resource_args(&self) -> Vec<String> {
113→        let mut args = Vec::new();
114→        let limits = &self.config.resource_limits;
115→        if let Some(ref mem) = limits.memory_limit {
116→            args.extend(["--memory".to_string(), mem.clone()]);
117→        }
118→        if let Some(cpu) = limits.cpu_quota {
119→            args.extend(["--cpus".to_string(), cpu.to_string()]);
120→        }
121→        if let Some(pids) = limits.pids_max {
122→            args.extend(["--pids-limit".to_string(), pids.to_string()]);
123→        }
124→        args
125→    }
126→
127→    pub(crate) fn network_run_args(&self) -> Vec<String> {
128→        match self.config.network {
129→            NetworkPolicy::Blocked => vec!["--network=none".to_string()],
130→            NetworkPolicy::Trusted => {
131→                // Ensure the container can reach the host proxy on all
132→                // platforms (Linux needs --add-host; macOS Docker Desktop
133→                // resolves host.docker.internal automatically).
134→                let gateway = self.resolve_host_gateway();
135→                vec![format!("--add-host=host.docker.internal:{gateway}")]
136→            },
137→            NetworkPolicy::Bypass => Vec::new(),
138→        }
139→    }
140→
141→    /// Resolve the IP that containers use to reach the host.
142→    ///
143→    /// Docker (and Podman >= 5.0) support the special `host-gateway` token in
144→    /// `--add-host`.  Older Podman versions reject it with:
145→    ///
146→    ///   Error: invalid IP address in add-host: "host-gateway"
147→    ///
148→    /// For those we resolve the address ourselves: rootless Podman (< 5.0) uses
149→    /// slirp4netns by default, which maps the host to `10.0.2.2`.  Rootful
150→    /// Podman uses a bridge whose gateway we can query via
151→    /// `podman network inspect`.
152→    pub(crate) fn resolve_host_gateway(&self) -> String {
153→        if self.kind != BackendKind::Podman {
154→            return "host-gateway".to_string();
155→        }
156→
157→        if podman_supports_host_gateway() {
158→            return "host-gateway".to_string();
159→        }
160→
161→        // Podman < 5.0 — resolve the address manually.
162→        podman_resolve_host_ip().unwrap_or_else(|| {
163→            debug!(
164→                "could not resolve host gateway IP for podman; \
165→                 falling back to host-gateway (may fail)"
166→            );
167→            "host-gateway".to_string()
168→        })
169→    }
170→
171→    pub(crate) fn proxy_exec_env_args(&self) -> Vec<String> {
172→        if self.config.network != NetworkPolicy::Trusted {
173→            return Vec::new();
174→        }
175→        let proxy_url = format!(
176→            "http://host.docker.internal:{}",
177→            moltis_network_filter::DEFAULT_PROXY_PORT
178→        );
179→        let mut args = Vec::new();
180→        for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
181→            args.extend(["-e".to_string(), format!("{key}={proxy_url}")]);
182→        }
183→        for key in ["NO_PROXY", "no_proxy"] {
184→            args.extend(["-e".to_string(), format!("{key}=localhost,127.0.0.1,::1")]);
185→        }
186→        args
187→    }
188→
189→    /// Security hardening flags for `docker run`.
190→    ///
191→    /// `is_prebuilt` controls whether `--read-only` is applied: prebuilt images
192→    /// already have packages baked in so the root FS can be read-only, while
193→    /// non-prebuilt images need a writable root for `apt-get` provisioning.
194→    pub(crate) fn hardening_args(is_prebuilt: bool, kind: BackendKind) -> Vec<String> {
195→        let mut args = vec![
196→            // --- Capability / privilege ---
197→            "--cap-drop".to_string(),
198→            "ALL".to_string(),
199→            "--security-opt".to_string(),
200→            "no-new-privileges".to_string(),
201→            // --- Writable tmpfs mounts ---
202→            "--tmpfs".to_string(),
203→            "/tmp:rw,nosuid,size=256m".to_string(),
204→            "--tmpfs".to_string(),
205→            "/run:rw,nosuid,size=64m".to_string(),
206→            // --- Host metadata isolation ---
207→            // Give the container its own hostname so /proc/sys/kernel/hostname
208→            // and the `hostname` command do not reveal the host identity.
209→            "--hostname".to_string(),
210→            "sandbox".to_string(),
211→        ];
212→        // Mask /sys subtrees that expose host hardware identifiers
213→        // (serial numbers, BIOS/UEFI data, disk models, LUKS UUIDs).
214→        // Empty read-only tmpfs overlays hide the underlying sysfs entries.
215→        //
216→        // Podman is excluded: its OCI runtime performs "tmpcopyup" on sysfs
217→        // tmpfs mounts, copying directory contents into the tmpfs first.
218→        // With --cap-drop ALL some sysfs files are permission-denied even for
219→        // root, causing the mount (and container startup) to fail.  Podman
220→        // already masks /sys/firmware via its built-in OCI MaskedPaths.
221→        if kind != BackendKind::Podman {
222→            args.extend([
223→                "--tmpfs".to_string(),
224→                "/sys/firmware:ro,nosuid".to_string(),
225→                "--tmpfs".to_string(),
226→                "/sys/class/dmi:ro,nosuid".to_string(),
227→                "--tmpfs".to_string(),
228→                "/sys/devices/virtual/dmi:ro,nosuid".to_string(),
229→                "--tmpfs".to_string(),
230→                "/sys/class/block:ro,nosuid".to_string(),
231→            ]);
232→        }
233→        if is_prebuilt {
234→            args.push("--read-only".to_string());
235→        }
236→        args
237→    }
238→
239→    pub(crate) fn workspace_args(&self) -> Vec<String> {
240→        let guest_workspace_dir = moltis_config::data_dir();
241→        let host_workspace_dir = host_visible_data_dir(&self.config, Some(self.cli));
242→        let guest_workspace_dir_str = guest_workspace_dir.display().to_string();
243→        let host_workspace_dir_str = host_workspace_dir.display().to_string();
244→        match self.config.workspace_mount {
245→            WorkspaceMount::Ro => vec![
246→                "-v".to_string(),
247→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:ro"),
248→            ],
249→            WorkspaceMount::Rw => vec![
250→                "-v".to_string(),
251→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:rw"),
252→            ],
253→            WorkspaceMount::None => Vec::new(),
254→        }
255→    }
256→
257→    pub(crate) fn home_persistence_args(&self, id: &SandboxId) -> Result<Vec<String>> {
258→        let Some(host_dir) =
259→            ensure_sandbox_home_persistence_host_dir(&self.config, Some(self.cli), id)?
260→        else {
261→            return Ok(Vec::new());
262→        };
263→        let volume = format!("{}:{SANDBOX_HOME_DIR}:rw", host_dir.display());
264→        Ok(vec!["-v".to_string(), volume])
265→    }
266→
267→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
268→        if sandbox_image_exists(self.cli, requested_image).await {
269→            return Ok(requested_image.to_string());
270→        }
271→
272→        let base_image = self.image().to_string();
273→        let packages = self.config.packages.clone();
274→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
275→            requested_image,
276→            self.image_repo(),
277→            &base_image,
278→            &packages,
279→        ) else {
280→            return Ok(requested_image.to_string());
281→        };
282→
283→        if requested_image == rebuild_tag {
284→            info!(
285→                image = requested_image,
286→                "sandbox image missing locally, rebuilding on demand"
287→            );
288→        } else {
289→            warn!(
290→                requested = requested_image,
291→                rebuilt = %rebuild_tag,
292→                "requested sandbox image missing locally, using deterministic tag from current config"
293→            );
294→        }
295→
296→        let Some(result) = self.build_image(&base_image, &packages).await? else {
297→            return Ok(requested_image.to_string());
298→        };
299→        Ok(result.tag)
300→    }
301→}
302→
303→#[async_trait]
304→impl Sandbox for DockerSandbox {
305→    fn backend_name(&self) -> &'static str {
306→        self.backend_label
307→    }
308→
309→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
310→        let name = self.container_name(id);
311→
312→        // Check if container already running.
313→        let check = tokio::process::Command::new(self.cli)
314→            .args(["inspect", "--format", "{{.State.Running}}", &name])
315→            .output()
316→            .await;
317→
318→        if let Ok(output) = check {
319→            let stdout = String::from_utf8_lossy(&output.stdout);
320→            if stdout.trim() == "true" {
321→                return Ok(());
322→            }
323→        }
324→
325→        // Resolve image first so we know whether it's prebuilt (affects hardening).
326→        let requested_image = image_override.unwrap_or_else(|| self.image());
327→        let image = self.resolve_local_image(requested_image).await?;
328→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
329→
330→        // Start a new container.
331→        let mut args = vec![
332→            "run".to_string(),
333→            "-d".to_string(),
334→            "--name".to_string(),
335→            name.clone(),
336→        ];
337→
338→        args.extend(self.network_run_args());
339→
340→        if let Some(ref tz) = self.config.timezone {
341→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
342→        }
343→
344→        args.extend(self.resource_args());
345→        args.extend(Self::hardening_args(is_prebuilt, self.kind));
346→        args.extend(self.workspace_args());
347→        args.extend(self.home_persistence_args(id)?);
348→
349→        args.push(image.clone());
350→        args.extend(["sleep".to_string(), "infinity".to_string()]);
351→
352→        let output = tokio::process::Command::new(self.cli)
353→            .args(&args)
354→            .output()
355→            .await?;
356→
357→        if !output.status.success() {
358→            let stderr = String::from_utf8_lossy(&output.stderr);
359→            return Err(Error::message(format!(
360→                "{} run failed: {}",
361→                self.cli,
362→                stderr.trim()
363→            )));
364→        }
365→
366→        // Skip provisioning if the image is a pre-built instance sandbox image
367→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
368→        if !is_prebuilt {
369→            provision_packages(self.cli, &name, &self.config.packages).await?;
370→        }
371→
372→        Ok(())
373→    }
374→
375→    async fn build_image(
376→        &self,
377→        base: &str,
378→        packages: &[String],
379→    ) -> Result<Option<BuildImageResult>> {
380→        if packages.is_empty() {
381→            return Ok(None);
382→        }
383→
384→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
385→
386→        // Check if image already exists.
387→        if sandbox_image_exists(self.cli, &tag).await {
388→            info!(
389→                tag,
390→                "pre-built sandbox image already exists, skipping build"
391→            );
392→            return Ok(Some(BuildImageResult { tag, built: false }));
393→        }
394→
395→        // Generate Dockerfile in a temp dir.
396→        let tmp_dir =
397→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
398→        std::fs::create_dir_all(&tmp_dir)?;
399→
400→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
401→        let dockerfile = sandbox_image_dockerfile(base, packages);
402→        let dockerfile_path = tmp_dir.join("Dockerfile");
403→        std::fs::write(&dockerfile_path, &dockerfile)?;
404→
405→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
406→
407→        let output = tokio::process::Command::new(self.cli)
408→            .args(["build", "-t", &tag, "-f"])
409→            .arg(&dockerfile_path)
410→            .arg(&tmp_dir)
411→            .stdout(std::process::Stdio::piped())
412→            .stderr(std::process::Stdio::piped())
413→            .output()
414→            .await;
415→
416→        // Clean up temp dir regardless of result.
417→        let _ = std::fs::remove_dir_all(&tmp_dir);
418→
419→        let output = output?;
420→        if !output.status.success() {
421→            let stderr = String::from_utf8_lossy(&output.stderr);
422→            return Err(Error::message(format!(
423→                "{} build failed for {tag}: {}",
424→                self.cli,
425→                stderr.trim()
426→            )));
427→        }
428→
429→        info!(tag, "pre-built sandbox image ready");
430→        Ok(Some(BuildImageResult { tag, built: true }))
431→    }
432→
433→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
434→        let name = self.container_name(id);
435→
436→        let mut args = vec!["exec".to_string()];
437→
438→        if let Some(ref dir) = opts.working_dir {
439→            args.extend(["-w".to_string(), dir.display().to_string()]);
440→        }
441→
442→        // Inject proxy env vars so traffic routes through the trusted-network
443→        // proxy running on the host.
444→        args.extend(self.proxy_exec_env_args());
445→
446→        for (k, v) in &opts.env {
447→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
448→        }
449→
450→        args.push(name);
451→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
452→
453→        let child = tokio::process::Command::new(self.cli)
454→            .args(&args)
455→            .stdout(std::process::Stdio::piped())
456→            .stderr(std::process::Stdio::piped())
457→            .stdin(std::process::Stdio::null())
458→            .spawn()?;
459→
460→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
461→
462→        match result {
463→            Ok(Ok(output)) => {
464→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
465→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
466→
467→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
468→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
469→
470→                Ok(ExecResult {
471→                    stdout,
472→                    stderr,
473→                    exit_code: output.status.code().unwrap_or(-1),
474→                })
475→            },
476→            Ok(Err(e)) => {
477→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
478→            },
479→            Err(_) => {
480→                return Err(Error::message(format!(
481→                    "{} exec timed out after {}s",
482→                    self.cli,
483→                    opts.timeout.as_secs()
484→                )));
485→            },
486→        }
487→    }
488→
489→    async fn read_file(
490→        &self,
491→        id: &SandboxId,
492→        file_path: &str,
493→        max_bytes: u64,
494→    ) -> Result<SandboxReadResult> {
495→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
496→            return native_host_read_file(
497→                host_path
498→                    .to_str()
499→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
500→                max_bytes,
501→            )
502→            .await;
503→        }
504→
505→        let container_name = self.container_name(id);
506→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
507→    }
508→
509→    async fn write_file(
510→        &self,
511→        id: &SandboxId,
512→        file_path: &str,
513→        content: &[u8],
514→    ) -> Result<Option<serde_json::Value>> {
515→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
516→            return native_host_write_file(
517→                host_path
518→                    .to_str()
519→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
520→                content,
521→            )
522→            .await;
523→        }
524→
525→        let container_name = self.container_name(id);
526→        oci_container_write_file(self.cli, &container_name, file_path, content).await
527→    }
528→
529→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
530→        if let Some(host_path) = self.mounted_host_path(id, root) {
531→            let host_files = native_host_list_files(
532→                host_path
533→                    .to_str()
534→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
535→            )
536→            .await?;
537→            return remap_host_list_result_to_guest(root, &host_path, host_files);
538→        }
539→
540→        let container_name = self.container_name(id);
541→        oci_container_list_files(self.cli, &container_name, root).await
542→    }
543→
544→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
545→        let name = self.container_name(id);
546→        let _ = tokio::process::Command::new(self.cli)
547→            .args(["rm", "-f", &name])
548→            .output()
549→            .await;
550→        Ok(())
551→    }
552→}
