560→        "none"
561→    }
562→
563→    fn is_real(&self) -> bool {
564→        false
565→    }
566→
567→    async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
568→        Ok(())
569→    }
