602→/// Return `true` when the installed Podman version supports `host-gateway`
603→/// in `--add-host` (added in Podman 5.0).
604→pub(crate) fn podman_supports_host_gateway() -> bool {
605→    let Ok(output) = std::process::Command::new("podman")
606→        .args(["version", "--format", "{{.Client.Version}}"])
607→        .output()
608→    else {
609→        return false;
610→    };
611→    let version_str = String::from_utf8_lossy(&output.stdout);
612→    let major: u32 = version_str
613→        .trim()
614→        .split('.')
615→        .next()
616→        .and_then(|s| s.parse().ok())
617→        .unwrap_or(0);
618→    major >= 5
619→}
