621→/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
622→/// host.  Rootless Podman defaults to slirp4netns where the host is always
623→/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
624→/// with `podman network inspect`.
625→pub(crate) fn podman_resolve_host_ip() -> Option<String> {
626→    let rootless = std::process::Command::new("podman")
627→        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
628→        .output()
629→        .ok()
630→        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
631→
632→    if rootless.as_deref() == Some("true") {
633→        // slirp4netns (default rootless network before Podman 5.0) maps the
634→        // host to 10.0.2.2.
635→        return Some("10.0.2.2".to_string());
636→    }
637→
638→    // Rootful — ask for the gateway of the default "podman" network.
639→    let output = std::process::Command::new("podman")
640→        .args([
641→            "network",
642→            "inspect",
643→            "podman",
644→            "--format",
645→            "{{(index .Subnets 0).Gateway}}",
646→        ])
647→        .output()
648→        .ok()?;
649→    let gateway = String::from_utf8_lossy(&output.stdout).trim().to_string();
650→    if gateway.is_empty() {
651→        None
652→    } else {
653→        Some(gateway)
654→    }
