/// Return the last `n` lines of `text`, or the full text if it has fewer lines.
fn tail_lines(text: &str, n: usize) -> String {
    let lines: Vec<&str> = text.lines().collect();
    if lines.len() <= n {
        return text.to_string();
    }
    format!(
        "... [{} lines truncated]\n{}",
        lines.len() - n,
        lines[lines.len() - n..].join("\n")
    )
}

